#include<cstdio>
#include<vector>
#define rep(a,b,c) for(int c=(a);c<=(b);++c)
inline int read()
{
	int res=0;char ch=getchar();while(ch<'0'||ch>'9')ch=getchar();
	while(ch<='9'&&ch>='0')res=res*10+(ch^48),ch=getchar();return res;
}
inline void print(const int &p){if(p>9)print(p/10);putchar(p%10+'0');}
inline void pt(const int &p,const char &c='\n'){print(p<0?putchar('-'),-p:p);putchar(c);}
template<typename T> inline T max(const T&x,const T&y){return x<y?y:x;}
template<typename T> inline T min(const T&x,const T&y){return x<y?x:y;}
template<typename T> inline void Swap(T&x,T&y){T tmp=x;x=y;y=tmp;}
const int N=4e5+10,INF=0x3f3f3f3f;int n,m;typedef long long ll;ll ans;
int fa[N],ch[N][2],mx[N],vl[N],s1[N],siz[N];bool tg[N];ll s2[N];
int faa[N];
inline bool nrt(int x){return ch[fa[x]][0]==x||ch[fa[x]][1]==x;}
inline void update(int x){siz[x]=siz[ch[x][0]]+siz[ch[x][1]]+s1[x]+1;}
inline void rotate(int x)
{
	int y=fa[x],z=fa[y];const bool &k=ch[y][1]==x;
	if(nrt(y))ch[z][ch[z][1]==y]=x;int w=ch[x][!k];ch[ch[x][!k]=y][k]=w;
	if(w)fa[w]=y;fa[fa[y]=x]=z;update(y);
}
inline void splay(int x)
{
	int y=fa[x];while(nrt(x)){if(nrt(y=fa[x]))rotate((ch[fa[y]][0]==y)^(ch[y][0]==x)?x:y);rotate(x);}update(x);
}
inline void access(int x)
{
	for(int y=0;x;x=fa[y=x])
	{
		splay(x);
//		printf("access %d :: %d %lld %d %d %d %d\n",x,s1[x],s2[x],y,ch[x][1],siz[y],siz[ch[x][1]]);
		s1[x]+=siz[ch[x][1]]-siz[y];
		s2[x]+=1ll*siz[ch[x][1]]*siz[ch[x][1]]-1ll*siz[y]*siz[y];
		
		ch[x][1]=y;update(x);
	}
}
inline int fndRt(int x){access(x);splay(x);while(ch[x][0])x=ch[x][0];splay(x);return x;}
inline void lnk(int x,int y)
{
	splay(x);ans-=s2[x]+1ll*siz[ch[x][1]]*siz[ch[x][1]];
	int rt=fndRt(y);access(x);splay(rt);ans-=1ll*siz[ch[rt][1]]*siz[ch[rt][1]];
//	printf("c1 :: %lld\n",ans);
	fa[x]=y;splay(y);s1[y]+=siz[x];s2[y]+=1ll*siz[x]*siz[x];
	update(y);access(x);splay(rt);ans+=1ll*siz[ch[rt][1]]*siz[ch[rt][1]];
//	printf("c2 :: %lld %d %d\n",ans,rt,ch[rt][1]);
//	printf("lnk(%d,%d) :: %lld\n",x,y,ans);
}
inline void cut(int x,int y)
{
	access(x);ans+=s2[x];int rt=fndRt(y);access(x);splay(rt);
	ans-=1ll*siz[ch[rt][1]]*siz[ch[rt][1]];splay(x);ch[x][0]=fa[ch[x][0]]=0;
	update(x);splay(rt);ans+=1ll*siz[ch[rt][1]]*siz[ch[rt][1]];
//	printf("cut(%d,%d) :: %lld\n",x,y,ans);
}
struct nd{int u,t;};std::vector<nd> op[N];std::vector<int> G[N];int Q,c[N];ll d[N];bool col[N];
inline void getFa(int u,int fa=n+1){faa[u]=fa;for(int v:G[u])if(v!=fa)getFa(v,u);}
int main()
{
	n=read();Q=read();rep(1,n,i)op[c[i]=read()].push_back({i,0});rep(1,n+1,i)siz[i]=1;
	rep(2,n,i){int x=read(),y=read();G[x].push_back(y),G[y].push_back(x);} getFa(1); rep(1,n,i)lnk(i,faa[i]);
//	printf("QAQ :: %lld\n",ans);
//	rep(1,n,i)printf("%d ",faa[i]);puts("");
	rep(1,Q,i)
	{
		int u=read(),v=read();
		op[c[u]].push_back({u,i});
		op[c[u]=v].push_back({u,i});
	}
	rep(1,n,i)if(op[i].size())
	{
		ll lst=0;if(op[i][0].t)lst=1ll*n*n,d[0]+=1ll*n*n;
		for(unsigned j=0;j<op[i].size();++j)
		{
//			printf("cnm :: %d\n",op[i][j].u);
			nd v=op[i][j];if(col[v.u]^=1)cut(v.u,faa[v.u]);else lnk(v.u,faa[v.u]);
			if(j+1>=op[i].size()||op[i][j+1].t!=v.t){d[v.t]+=ans-lst;lst=ans;}
		}
		for(unsigned j=op[i].size()-1;~j;--j)
			{int u=op[i][j].u;if(col[u]^=1)cut(u,faa[u]);else lnk(u,faa[u]);}
	}
	else {d[0]+=1ll*n*n;}
	ll ans=1ll*n*n*n;rep(0,Q,i)printf("%lld\n",ans-=d[i]);puts("");
	
}
